__global__ void srad_kernel(fp lambda, int Nr, int Nc, long Ne, int *d_iN, int *d_iS, int *d_jE, int *d_jW, fp *d_dN, fp *d_dS, fp *d_dW, fp *d_dE, fp q0sqr, fp *d_c, fp *d_I) {
    int i = blockIdx.x;
    int j = threadIdx.x;

    if (i < Nr && j < Nc) {
        int k = i * Nc + j;
        fp Jc = d_I[k];

        int iN_idx = d_iN[i];
        int iS_idx = d_iS[i];
        int jW_idx = d_jW[j];
        int jE_idx = d_jE[j];

        fp dN_val = d_I[iN_idx * Nc + j] - Jc;
        fp dS_val = d_I[iS_idx * Nc + j] - Jc;
        fp dW_val = d_I[i * Nc + jW_idx] - Jc;
        fp dE_val = d_I[i * Nc + jE_idx] - Jc;

        d_dN[k] = dN_val;
        d_dS[k] = dS_val;
        d_dW[k] = dW_val;
        d_dE[k] = dE_val;

        fp G2 = (dN_val * dN_val + dS_val * dS_val + dW_val * dW_val + dE_val * dE_val) / (Jc * Jc);
        fp L = (dN_val + dS_val + dW_val + dE_val) / Jc;

        fp num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
        fp den = 1.0f + (0.25f * L);
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        fp c_val = 1.0f / (1.0f + den);

        if (c_val < 0.0f) c_val = 0.0f;
        else if (c_val > 1.0f) c_val = 1.0f;

        d_c[k] = c_val;
    }
}

